198	    where
199	        F: Future + Send + 'static,
200	        F::Output: Send + 'static,

444	    ///    runtime.block_on(async move {
445	    ///        task::spawn_blocking(move || {
446	    ///            thread::sleep(Duration::from_secs(10_000));
447	    ///        });
448	    ///    });
449	    ///
450	    ///    runtime.shutdown_timeout(Duration::from_millis(100));
451	    /// }
