460	    /// Shuts down the runtime, without waiting for any spawned work to stop.
461	    ///
462	    /// This can be useful if you want to drop a runtime from within another runtime.
463	    /// Normally, dropping a runtime will block indefinitely for spawned blocking tasks
464	    /// to complete, which would normally not be permitted within an asynchronous context.
465	    /// By calling `shutdown_background()`, you can drop the runtime from such a context.
466	    ///
467	    /// Note however, that because we do not wait for any blocking tasks to complete, this
468	    /// may result in a resource leak (in that any blocking tasks are still running until they
469	    /// return.
470	    ///
471	    /// See the [struct level documentation](Runtime#shutdown) for more details.
472	    ///
473	    /// This function is equivalent to calling `shutdown_timeout(Duration::from_nanos(0))`.
474	    ///
475	    /// ```
476	    /// # #[cfg(not(target_family = "wasm"))]
477	    /// # {
478	    /// use tokio::runtime::Runtime;
479	    ///
480	    /// fn main() {
481	    ///    let runtime = Runtime::new().unwrap();
482	    ///
483	    ///    runtime.block_on(async move {
484	    ///        let inner_runtime = Runtime::new().unwrap();
485	    ///        // ...
486	    ///        inner_runtime.shutdown_background();
487	    ///    });
488	    /// }
489	    /// # }
490	    /// ```
491	    pub fn shutdown_background(self) {
492	        self.shutdown_timeout(Duration::from_nanos(0));
493	    }
