502	impl Drop for Runtime {
503	    fn drop(&mut self) {
504	        match &mut self.scheduler {
505	            Scheduler::CurrentThread(current_thread) => {
506	                // This ensures that tasks spawned on the current-thread
507	                // runtime are dropped inside the runtime's context.
508	                let _guard = context::try_set_current(&self.handle.inner);
509	                current_thread.shutdown(&self.handle.inner);
510	            }
511	            #[cfg(feature = "rt-multi-thread")]
512	            Scheduler::MultiThread(multi_thread) => {
513	                // The threaded scheduler drops its tasks on its worker threads, which is
514	                // already in the runtime's context.
515	                multi_thread.shutdown(&self.handle.inner);
516	            }
517	        }
518	    }
519	}
