525	fn display_eq(d: impl std::fmt::Display, s: &str) -> bool {
526	    use std::fmt::Write;
527	
528	    struct FormatEq<'r> {
529	        remainder: &'r str,
530	        unequal: bool,
531	    }
532	
533	    impl<'r> Write for FormatEq<'r> {
534	        fn write_str(&mut self, s: &str) -> std::fmt::Result {
535	            if !self.unequal {
536	                if let Some(new_remainder) = self.remainder.strip_prefix(s) {
537	                    self.remainder = new_remainder;
538	                } else {
539	                    self.unequal = true;
540	                }
541	            }
542	            Ok(())
543	        }
544	    }
545	
546	    let mut fmt_eq = FormatEq {
547	        remainder: s,
548	        unequal: false,
549	    };
550	    let _ = write!(fmt_eq, "{d}");
551	    fmt_eq.remainder.is_empty() && !fmt_eq.unequal
552	}
