554	/// Checks whether the given error was emitted by Tokio when shutting down its runtime.
555	///
556	/// # Examples
557	///
558	/// ```
559	/// # #[cfg(not(target_family = "wasm"))]
560	/// # {
561	/// use tokio::runtime::Runtime;
562	/// use tokio::net::TcpListener;
563	///
564	/// fn main() {
565	///     let rt1 = Runtime::new().unwrap();
566	///     let rt2 = Runtime::new().unwrap();
567	///
568	///     let listener = rt1.block_on(async {
569	///         TcpListener::bind("127.0.0.1:0").await.unwrap()
570	///     });
571	///
572	///     drop(rt1);
573	///
574	///     rt2.block_on(async {
575	///         let res = listener.accept().await;
576	///         assert!(res.is_err());
577	///         assert!(tokio::runtime::is_rt_shutdown_err(res.as_ref().unwrap_err()));
578	///     });
579	/// }
580	/// # }
581	/// ```
582	pub fn is_rt_shutdown_err(err: &io::Error) -> bool {
583	    if let Some(inner) = err.get_ref() {
584	        err.kind() == io::ErrorKind::Other
585	            && inner.source().is_none()
586	            && display_eq(inner, RUNTIME_SHUTTING_DOWN_ERROR)
587	    } else {
588	        false
589	    }
590	}
